from flask import Flask, request, render_template, redirect, url_for, session, flash
from werkzeug.security import generate_password_hash, check_password_hash
import pyotp
import qrcode
import io
import base64
from flask import jsonify

app = Flask(__name__)
app.secret_key = 'your-secret-key-here'

# Mock user database
users = {
    'admin': {
        'password': generate_password_hash('password123'),
        'totp_secret': 'JBSWY3DPEHPK3PXP'
    }
}

# Mock session storage
active_sessions = {}

@app.route('/login', methods=['GET', 'POST'])
def login():
    if request.method == 'POST':
        username = request.form.get('username')
        password = request.form.get('password')
        
        if username in users and check_password_hash(users[username]['password'], password):
            # Store user in session
            session['user_id'] = username
            session['mfa_verified'] = False
            
            # Generate TOTP secret if not exists
            if 'totp_secret' not in users[username]:
                users[username]['totp_secret'] = pyotp.random_base32()
            
            # Redirect to MFA verification
            return redirect(url_for('verify_mfa'))
        else:
            flash('Invalid username or password')
            return redirect(url_for('login'))
    
    return render_template('login.html')

@app.route('/verify-mfa', methods=['GET', 'POST'])
def verify_mfa():
    if 'user_id' not in session:
        return redirect(url_for('login'))
    
    user_id = session['user_id']
    
    if request.method == 'POST':
        totp_code = request.form.get('totp_code')
        
        # Verify TOTP code
        totp = pyotp.TOTP(users[user_id]['totp_secret'])
        if totp.verify(totp_code, valid_window=1):
            session['mfa_verified'] = True
            return redirect(url_for('dashboard'))
        else:
            flash('Invalid verification code')
            return redirect(url_for('verify_mfa'))
    
    # Generate QR code for MFA setup
    totp_uri = pyotp.totp.TOTP(users[user_id]['totp_secret']).provisioning_uri(
        user_id, issuer_name="MyApp"
    )
    
    # Generate QR code image
    qr = qrcode.QRCode(version=1, box_size=10, border=4)
    qr.add_data(totp_uri)
    qr.make(fit=True)
    
    img = qr.make_image(fill_color="black", back_color="white")
    img_buffer = io.BytesIO()
    img.save(img_buffer)
    img_buffer.seek(0)
    
    qr_code = base64.b64encode(img_buffer.getvalue()).decode()
    
    return render_template('verify_mfa.html', qr_code=qr_code, totp_uri=totp_uri)

@app.route('/dashboard')
def dashboard():
    if 'user_id' not in session or not session.get('mfa_verified', False):
        return redirect(url_for('login'))
    
    return f"Welcome {session['user_id']}! This is a protected resource."

@app.route('/api/protected')
def protected_api():
    if 'user_id' not in session or not session.get('mfa_verified', False):
        return jsonify({'error': 'Unauthorized'}), 401
    
    return jsonify({'message': 'This is a protected API endpoint'})

if __name__ == '__main__':
    app.run(debug=True)